mapper.update:
update cotdl.tbl_piicontract
set
	status= #{status, jdbcType=VARCHAR},
	real_doc_del_date= now(),
	real_doc_del_userid= #{real_doc_del_userid, jdbcType=VARCHAR}
where custid= #{custid, jdbcType=VARCHAR} and contractno= #{contractno, jdbcType=VARCHAR}

mapper.select:

	select mon, mgmt_dept_cd, mgmt_dept_name, acount, ncount, ycount, concat(ROUND(ycount/acount,1)*100,'%') as progress
	from(
		select DATE_FORMAT(arc_del_date,'%Y/%m') as mon, mgmt_dept_cd, mgmt_dept_name, count(1) as acount, COUNT(case when status = 'N' then 1 end) as ncount, COUNT(case when status = 'Y' then 1 end) as ycount
		  from cotdl.tbl_piicontract
		
		
		
		 group by DATE_FORMAT(arc_del_date,'%Y/%m'), mgmt_dept_cd, mgmt_dept_name
	 ) a
	where
	  mon is not null
	 order by mon , mgmt_dept_cd, mgmt_dept_name
limit #{offset}, #{amount}
